import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import './Pages.css';

const CloseAccount = () => {
  const [language, setLanguage] = useState('en');
  const [customers, setCustomers] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState('');
  const [searchName, setSearchName] = useState('');
  const [filteredCustomers, setFilteredCustomers] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [accountDetails, setAccountDetails] = useState(null);
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(false);
  const [interestRate, setInterestRate] = useState(7);
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().split('T')[0]);
  const [amountPaying, setAmountPaying] = useState(0);
  const [isPartialPayment, setIsPartialPayment] = useState(false);
  const [selectedBills, setSelectedBills] = useState([]);

  const translations = {
    en: { 
      closeAccount: 'Close Account', 
      selectCustomer: 'Select Customer', 
      bills: 'Bills', 
      noData: 'No data available', 
      billNumber: 'Bill Number',
      date: 'Date', 
      purchasedDate: 'Purchased Date',
      paymentDate: 'Payment Date',
      items: 'Items',
      subtotal: 'Total',
      paidAmount: 'Paid Amount',
      pendingAmount: 'Pending Amount',
      interest: 'Interest',
      finalAmount: 'Final Amount',
      grandTotal: 'Grand Total',
      amount: 'Amount', 
      village: 'Village',
      select: 'Select',
      amountToPay: 'Amount to Pay',
      amountPaying: 'Amount Paying',
      balanceAfterPaying: 'Balance After Paying',
      savePayment: 'Save Payment'
    },
    te: { 
      closeAccount: 'ఖాతా మూసివేయి', 
      selectCustomer: 'కస్టమర్‌ను ఎంచుకోండి', 
      bills: 'బిల్లులు', 
      noData: 'డేటా లేదు', 
      billNumber: 'బిల్ నంబర్',
      date: 'తేదీ', 
      purchasedDate: 'కొన్న తేదీ',
      paymentDate: 'చెల్లించే తేదీ',
      items: 'సరుకులు',
      subtotal: 'మొత్తం',
      paidAmount: 'చెల్లిన మొత్తం',
      pendingAmount: 'బకాయి మొత్తం',
      interest: 'వడ్డీ',
      finalAmount: 'చివరి మొత్తం',
      grandTotal: 'మొత్తం',
      amount: 'మొత్తం', 
      village: 'గ్రామం',
      select: 'ఎంచుకోండి',
      amountToPay: 'చెల్లించవలసిన మొత్తం',
      amountPaying: 'చెల్లుస్తున్న మొత్తం',
      balanceAfterPaying: 'చెల్లించిన తర్వాత బాకీ',
      savePayment: 'చెల్లింపు సేవ్ చేయండి'
    },
    hi: { 
      closeAccount: 'खाता बंद करें', 
      selectCustomer: 'ग्राहक चुनें', 
      bills: 'बिल', 
      noData: 'कोई डेटा नहीं', 
      billNumber: 'बिल नंबर',
      date: 'तारीख', 
      purchasedDate: 'खरीद की तारीख',
      paymentDate: 'भुगतान की तारीख',
      items: 'वस्तुएं',
      subtotal: 'कुल',
      paidAmount: 'भुगतान की गई राशि',
      pendingAmount: 'बकाया राशि',
      interest: 'ब्याज',
      finalAmount: 'अंतिम राशि',
      grandTotal: 'कुल राशि',
      amount: 'राशि', 
      village: 'गाँव',
      select: 'चुनें',
      amountToPay: 'भुगतान करने की राशि',
      amountPaying: 'राशि भुगतान करना',
      balanceAfterPaying: 'भुगतान के बाद शेष राशि',
      savePayment: 'भुगतान सहेजें'
    }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchCustomers();
  }, []);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/customers', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    }
  };

  const handleSelectCustomer = async (customerName) => {
  setLoading(true);

  try {
    const token = localStorage.getItem('token');

    // ✅ get all customers with same name
    const matchedCustomers = customers.filter(
      c => c.customerName === customerName
    );

    if (matchedCustomers.length === 0) {
      alert('Customer not found');
      setLoading(false);
      return;
    }

    // Store the first matched customer's ID
    const customerId = matchedCustomers[0]._id;
    setSelectedCustomer(customerId);

    let allBills = [];

    for (let customer of matchedCustomers) {
      const response = await axios.get(
        `http://localhost:5000/api/bills/customer/${customer._id}`,
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );

      allBills = [...allBills, ...(response.data.bills || [])];
    }

    setBills(allBills);

  } catch (err) {
    console.error('Error:', err);
  } finally {
    setLoading(false);
  }
};

  // ✅ LIVE SEARCH
  const handleSearchChange = (value) => {
    setSearchName(value);

    if (!value.trim()) {
      setFilteredCustomers([]);
      setShowSuggestions(false);
      return;
    }

    const filtered = customers.filter(c =>
      c.customerName.toLowerCase().includes(value.toLowerCase())
    );

    setFilteredCustomers(filtered);
    setShowSuggestions(true);
  };
// ✅ ADD HERE (~line 155)
  // ✅ SELECT FROM SUGGESTION
  const handleSelectSuggestion = async (customer) => {
    setSearchName(customer.customerName);
    setShowSuggestions(false);
    setSelectedCustomer(customer._id);

    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(
        `http://localhost:5000/api/bills/customer/${customer._id}`,
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );
      setBills(response.data.bills || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const toggleSelect = (billId) => {
    setSelectedBills(prev =>
      prev.includes(billId)
        ? prev.filter(id => id !== billId)
        : [...prev, billId]
    );
  };

  const calculateTotalAmountToPay = () => {
    return bills
      .filter(bill => selectedBills.includes(bill._id))
      .reduce((total, bill) => {
        const purchaseDate = new Date(bill.createdAt);
        const paymentDateObj = new Date(paymentDate);
        const purchaseDateOnly = new Date(
          purchaseDate.getFullYear(),
          purchaseDate.getMonth(),
          purchaseDate.getDate()
        );
        const paymentDateOnly = new Date(
          paymentDateObj.getFullYear(),
          paymentDateObj.getMonth(),
          paymentDateObj.getDate()
        );
        const days = Math.max(
          0,
          Math.round((paymentDateOnly - purchaseDateOnly) / (1000 * 60 * 60 * 24)) - 1
        );
        const interest = bill.pendingAmount > 0
          ? (bill.pendingAmount * interestRate * days) / (365 * 7)
          : 0;
        const finalAmount = bill.pendingAmount + interest;
        return total + finalAmount;
      }, 0);
  };

  const handleSavePayment = async () => {
    try {
      if (!selectedCustomer) {
        alert('Please select a customer');
        return;
      }

      if (selectedBills.length === 0) {
        alert('Please select at least one bill');
        return;
      }

      const token = localStorage.getItem('token');
      const totalAmount = calculateTotalAmountToPay();

      // Call the closeAccount endpoint with the correct payload
      await axios.post(
        `http://localhost:5000/api/accounts/close`,
        {
          customerId: selectedCustomer,
          interestPercentage: interestRate,
          paymentAmount: amountPaying,
          partialPayment: amountPaying < totalAmount,
          paymentDate: paymentDate
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert('Payment saved successfully!');
      setAmountPaying(0);
      setSelectedBills([]);
      // Refresh bills after payment
      const response = await axios.get(
        `http://localhost:5000/api/bills/customer/${selectedCustomer}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setBills(response.data.bills || []);
    } catch (err) {
      console.error('Error:', err);
      alert('Failed to save payment: ' + (err.response?.data?.message || err.message));
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.closeAccount}</h1>
        </div>

        <div className="page-card">

          {/* ✅ SEARCH BOX */}
          <div className="form-group" style={{ position: 'relative' }}>
            <label>Search Customer</label>
            <input
              type="text"
              placeholder="Type name..."
              value={searchName}
              onChange={(e) => handleSearchChange(e.target.value)}
              style={{ padding: '10px', width: '100%' }}
            />

            {showSuggestions && filteredCustomers.length > 0 && (
              <div style={{
                position: 'absolute',
                background: '#fff',
                border: '1px solid #ddd',
                width: '100%',
                maxHeight: '200px',
                overflowY: 'auto',
                zIndex: 1000
              }}>
                {filteredCustomers.map(c => (
                  <div
                    key={c._id}
                    onClick={() => handleSelectSuggestion(c)}
                    style={{ padding: '10px', cursor: 'pointer' }}
                  >
                    <strong>{c.customerName}</strong><br />
                    <small>{c.phone} | {c.village}</small>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* OLD DROPDOWN (kept safe) */}
          <div className="form-group">
            <label>{t.selectCustomer}</label>
            <select value={selectedCustomer} onChange={(e) => handleSelectCustomer(e.target.value)}>
              <option value="">-- {t.selectCustomer} --</option>
              {[...new Map(customers.map(c => [c.customerName, c])).values()]
  .map(c => (
    <option key={c.customerName} value={c.customerName}>
      {c.customerName}
    </option>
))}
            </select>
          </div>

          <div className="form-group">
            <label>{t.paymentDate}</label>
            <input
              type="date"
              value={paymentDate}
              onChange={(e) => setPaymentDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>{t.interest} Rate (%)</label>
            <input
              type="number"
              min="0"
              value={interestRate}
              onChange={(e) => setInterestRate(parseFloat(e.target.value) || 0)}
            />
          </div>

          {selectedCustomer && (
            <div className="bills-table-container">
              <h2>{t.bills}</h2>

              {bills.length === 0 ? (
                <p>{t.noData}</p>
              ) : (
                <>
                  <table className="bills-table">
                    <thead>
                      <tr>
                        <th>{t.select}</th>
                        <th>{t.purchasedDate}</th>
                        <th>{t.paymentDate}</th>
                        <th>Days</th>
                        <th>{t.items}</th>
                        <th>{t.subtotal}</th>
                        <th>{t.paidAmount}</th>
                        <th>{t.pendingAmount}</th>
                        <th>{t.interest}</th>
                        <th>{t.finalAmount}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {bills.map((bill) => {
                        const purchaseDate = new Date(bill.createdAt);
                        const paymentDateObj = new Date(paymentDate);

                        const purchaseDateOnly = new Date(
                          purchaseDate.getFullYear(),
                          purchaseDate.getMonth(),
                          purchaseDate.getDate()
                        );
                        const paymentDateOnly = new Date(
                          paymentDateObj.getFullYear(),
                          paymentDateObj.getMonth(),
                          paymentDateObj.getDate()
                        );

                        const days = Math.max(
                          0,
                          Math.round((paymentDateOnly - purchaseDateOnly) / (1000 * 60 * 60 * 24)) - 1
                        );

                        const interest = selectedBills.includes(bill._id) && bill.pendingAmount > 0
                          ? (bill.pendingAmount * interestRate * days) / (365 * 7)
                          : 0;
                        const finalAmount = bill.pendingAmount + interest;

                        return (
                          <tr key={bill._id}>
                            <td>
                              <input
                                type="checkbox"
                                checked={selectedBills.includes(bill._id)}
                                onChange={() => toggleSelect(bill._id)}
                              />
                            </td>
                            <td>{purchaseDate.toLocaleDateString()}</td>
                            <td>{paymentDateObj.toLocaleDateString()}</td>
                            <td>{days}</td>
                            <td>{bill.items?.length}</td>
                            <td>₹ {bill.subtotal}</td>
                            <td>₹ {bill.paidAmount}</td>
                            <td>₹ {bill.pendingAmount}</td>
                            <td>₹ {interest.toFixed(2)}</td>
                            <td>₹ {finalAmount.toFixed(2)}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>

                  <div style={{ marginTop: '20px', padding: '15px', border: '1px solid #ddd', borderRadius: '5px', backgroundColor: '#f9f9f9' }}>
                    <div style={{ fontSize: '18px', fontWeight: 'bold', marginBottom: '15px' }}>
                      {t.amountToPay}: ₹ {calculateTotalAmountToPay().toFixed(2)}
                    </div>

                    <div className="form-group">
                      <label>{t.amountPaying}</label>
                      <input
                        type="number"
                        min="0"
                        value={amountPaying}
                        onChange={(e) => setAmountPaying(parseFloat(e.target.value) || 0)}
                        style={{ padding: '8px', width: '100%' }}
                      />
                    </div>

                    <div style={{ fontSize: '18px', fontWeight: 'bold', marginTop: '15px', marginBottom: '15px', color: '#333' }}>
                      {t.balanceAfterPaying}: ₹ {Math.max(0, calculateTotalAmountToPay() - amountPaying).toFixed(2)}
                    </div>

                    <button
                      onClick={handleSavePayment}
                      style={{
                        padding: '10px 20px',
                        backgroundColor: '#4CAF50',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '16px'
                      }}
                    >
                      {t.savePayment}
                    </button>
                  </div>
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CloseAccount;
